#include <stdio.h>
#include <string.h>

int main() {
    const char *drops[] = {
        "Healing Potion", "Mana Potion", "Sword", "Shield",
        "Healing Potion", "Gold Coins", "Sword", "Healing Potion"
    };
    const int D = 8;
    char line[256];
    if (!fgets(line, sizeof(line), stdin)) return 0;
    int T;
    sscanf(line, "%d", &T);
    for (int t = 0; t < T; ++t) {
        if (!fgets(line, sizeof(line), stdin)) break;
        size_t len = strlen(line);
        if (len && line[len-1] == '
') line[--len] = '\0';
        printf("Analyzing drops for: %s
", line);
        int count = 0, firstIdx = -1;
        for (int i = 0; i < D; ++i) {
            if (strcmp(line, drops[i]) == 0) {
                if (count == 0) firstIdx = i;
                ++count;
            }
        }
        if (count) {
            printf("'%s' dropped %d time(s).
", line, count);
            printf("It first appeared at drop number (index) %d.
", firstIdx);
        } else {
            printf("'%s' was not found in the drops.
", line);
        }
    }
    return 0;
}

