code.Python3:
#!/usr/bin/env python3
import sys

DROPS = [
    "Healing Potion", "Mana Potion", "Sword", "Shield",
    "Healing Potion", "Gold Coins", "Sword", "Healing Potion"
]

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        query = data[i].rstrip('
')
        out.append(f"Analyzing drops for: {query}")
        count = 0
        first_idx = -1
        for idx, item in enumerate(DROPS):
            if query == item:
                if count == 0:
                    first_idx = idx
                count += 1
        if count:
            out.append(f"'{query}' dropped {count} time(s).")
            out.append(f"It first appeared at drop number (index) {first_idx}.")
        else:
            out.append(f"'{query}' was not found in the drops.")
    sys.stdout.write("
".join(out))

if __name__ == "__main__":
    main()

